const availableRunActions = (
  state: GameState,
  knownFeatures: readonly BotKnownFeature[],
): readonly RunAction[] => {
  const actions: RunAction[] = [...getAvailableActions(state)];

  if (
    knownFeatures.some(
      (feature) =>
        feature.kind === "hoard" &&
        feature.depth === state.run.depth &&
        samePosition(feature.position, state.player.position),
    )
  ) {
    actions.unshift({ kind: "take_hoard" });
  }

  return actions;
};

const itemViewFromStack = (
  state: GameState,
  stack: PlayerItemStack,
  entityId: EntityId | null,
  equipped = false,
  position: Position | null = null,
): BotKnownItem => {
  const knowledge = itemCardKnowledge(state, stack.definition, {
    itemInstanceId: stack.itemInstanceId,
    identified: stack.identified,
  });
  const bundle = knowledge.effectsKnown ? activeEffectBundle(stack.definition) : null;

  return {
    itemInstanceId: stack.itemInstanceId,
    entityId,
    definitionId: stack.definition.id,
    category: knowledge.category,
    displayName: knowledge.displayName,
    position,
    quantity: stack.quantity,
    identified: stack.identified,
    effectsKnown: knowledge.effectsKnown,
    effects: bundle?.effects ?? [],
    bonusKnown: knowledge.bonusKnown,
    bonus: knowledge.knownBonus,
    equipped,
  };
};

const readInspectableFeatures = (
  state: GameState,
  fog: FogMemory | null,
): readonly BotKnownFeature[] => {
  const knowledge = floorKnowledge(state);
  const records = readDecorativeFeatureRecords(knowledge);

  return records.flatMap((record) => {
    const feature = parseHoardFeature(record);
    if (feature === null) {
      return [];
    }

    if (
      fog !== null &&
      !cellKnown(fog, feature.position, knowledge.mapRevealed === true)
    ) {
      return [];
    }

    return [feature];
  });
};

const parseHoardFeature = (record: SerializableRecord): BotKnownFeature | null => {
  if (
    record.kind !== "hoard" ||
    typeof record.id !== "string" ||
    typeof record.name !== "string" ||
    typeof record.x !== "number" ||
    typeof record.y !== "number" ||
    typeof record.depth !== "number" ||
    !Number.isSafeInteger(record.x) ||
    !Number.isSafeInteger(record.y) ||
    !Number.isSafeInteger(record.depth)
  ) {
    return null;
  }

  return {
    id: record.id,
    kind: "hoard",
    name: record.name,
    position: { x: record.x, y: record.y },
    depth: record.depth,
  };
};

const readDecorativeFeatureRecords = (knowledge: {
  readonly [key: string]: unknown;
}): readonly SerializableRecord[] => {
  const records = knowledge.decorativeFeatures;
  if (!Array.isArray(records)) {
    return [];
  }

  return records.filter(
    (record): record is SerializableRecord =>
      record !== null && typeof record === "object" && !Array.isArray(record),
  );
};

const entityCellVisible = (
  entity: EntityInstance,
  fog: FogMemory | null,
  mapRevealed: boolean,
): boolean => {
  if (fog === null) {
    return true;
  }

  const memory = fog.tiles[idx(fog, entity.position)];
  if (memory === undefined) {
    return false;
  }

  return mapRevealed || memory.state === "visible";
};

const cellKnown = (
  fog: FogMemory,
  position: Position,
  mapRevealed: boolean,
): boolean => {
  const memory = fog.tiles[idx(fog, position)];
  return memory !== undefined && !hiddenCell(memory, mapRevealed);
};

const hiddenCell = (memory: FogTileMemory, mapRevealed: boolean): boolean =>
  !mapRevealed && memory.state === "unseen";

const mergeFeatures = (
  features: readonly BotKnownFeature[],
): readonly BotKnownFeature[] =>
  [
    ...new Map(
      features.map((feature) => [
        `${feature.depth}:${feature.kind}:${feature.id}`,
        feature,
      ]),
    ).values(),
  ].sort((left, right) =>
    left.depth === right.depth
      ? left.id.localeCompare(right.id)
      : left.depth - right.depth,
  );

const positionsFromKeys = (keys: ReadonlySet<string>): readonly Position[] =>
  [...keys].sort().map((value) => {
    const [x, y] = value.split(",").map((part) => Number.parseInt(part, 10));
    return { x: x ?? 0, y: y ?? 0 };
  });

const ratio = (current: number, max: number): number =>
  max <= 0 ? 0 : current / max;

const samePosition = (left: Position, right: Position): boolean =>
  left.x === right.x && left.y === right.y;

const key = (position: Position): string => `${position.x},${position.y}`;

import type {
  EntityId,
  EntityInstance,
  GameState,
  InventorySlot,
  Position,
  SerializableRecord,
} from "../state/index.js";
import {
  chebyshevDistance,
  getTile,
  inBounds,
  isWalkableTile,
  Terrain,
  type TileGrid,
} from "../map/index.js";

export const MOVE_DIRECTIONS = [
  { direction: "northwest", offset: { x: -1, y: -1 } },
  { direction: "north", offset: { x: 0, y: -1 } },
  { direction: "northeast", offset: { x: 1, y: -1 } },
  { direction: "west", offset: { x: -1, y: 0 } },
  { direction: "east", offset: { x: 1, y: 0 } },
  { direction: "southwest", offset: { x: -1, y: 1 } },
  { direction: "south", offset: { x: 0, y: 1 } },
  { direction: "southeast", offset: { x: 1, y: 1 } },
] as const;

export type MoveDirection = (typeof MOVE_DIRECTIONS)[number]["direction"];

export type ActionTarget =
  | {
      readonly kind: "self";
    }
  | {
      readonly kind: "entity";
      readonly entityId: EntityId;
    }
  | {
      readonly kind: "cell";
      readonly cell: Position;
    };

export type MoveAction = {
  readonly kind: "move";
  readonly direction: MoveDirection;
};

export type AttackAction = {
  readonly kind: "attack";
  readonly targetId: EntityId;
};

export type UseItemAction = {
  readonly kind: "use_item";
  readonly itemId: string;
  readonly target?: ActionTarget;
  readonly direction?: MoveDirection;
};

export type PickupAction = {
  readonly kind: "pickup";
};

export type TalkAction = {
  readonly kind: "talk";
  readonly npcId: EntityId;
};

export type WaitAction = {
  readonly kind: "wait";
};

export type DescendAction = {
  readonly kind: "descend";
};

export type InspectAction = {
  readonly kind: "inspect";
  readonly cell: Position;
};

export type AbortAction = {
  readonly kind: "abort";
};

export type PlayerAction =
  | MoveAction
  | AttackAction
  | UseItemAction
  | PickupAction
  | TalkAction
  | WaitAction
  | DescendAction
  | InspectAction
  | AbortAction;

export type LegalActionResult = {
  readonly status: "legal";
};

export type IllegalActionResult = {
  readonly status: "illegal";
  readonly reason: string;
};

export type ActionLegality = LegalActionResult | IllegalActionResult;

export const LEGAL_ACTION = { status: "legal" } as const satisfies ActionLegality;

export const isActionLegal = (
  result: ActionLegality,
): result is LegalActionResult => result.status === "legal";

export const checkActionLegality = (
  state: GameState,
  action: PlayerAction,
): ActionLegality => {
  if (state.run.terminalStatus !== "ACTIVE") {
    return illegal(`run is terminal (${state.run.terminalStatus})`);
  }

  switch (action.kind) {
    case "move":
      return checkMoveAction(state, action);
    case "attack":
      return checkAttackAction(state, action);
    case "use_item":
      return checkUseItemAction(state, action);
    case "pickup":
      return checkPickupAction(state);
    case "talk":
      return checkTalkAction(state, action);
    case "wait":
      return LEGAL_ACTION;
    case "descend":
      return checkDescendAction(state);
    case "inspect":
      return checkInspectAction(state, action);
    case "abort":
      return LEGAL_ACTION;
  }
};

export const getAvailableActions = (state: GameState): readonly PlayerAction[] => {
  if (state.run.terminalStatus !== "ACTIVE") {
    return [];
  }

  const actions: PlayerAction[] = [];

  for (const { direction } of MOVE_DIRECTIONS) {
    const action = { kind: "move", direction } as const;
    pushIfLegal(actions, state, action);
  }

  for (const entity of sortedEntities(state)) {
    if (entity.kind === "enemy") {
      pushIfLegal(actions, state, {
        kind: "attack",
        targetId: entity.id,
      });
    }
  }

  for (const item of carriedItems(state.player.inventory)) {
    pushIfLegal(actions, state, {
      kind: "use_item",
      itemId: item.itemInstanceId,
    });
  }

  pushIfLegal(actions, state, { kind: "pickup" });

  for (const entity of sortedEntities(state)) {
    if (entity.kind === "npc") {
      pushIfLegal(actions, state, {
        kind: "talk",
        npcId: entity.id,
      });
    }
  }

  pushIfLegal(actions, state, { kind: "wait" });
  pushIfLegal(actions, state, { kind: "descend" });
  actions.push(...availableInspectActions(state));
  pushIfLegal(actions, state, { kind: "abort" });

  return actions;
};

export const destinationForMove = (
  origin: Position,
  direction: MoveDirection,
): Position => {
  const offset = offsetForDirection(direction);

  return {
    x: origin.x + offset.x,
    y: origin.y + offset.y,
  };
};

export const gridFromState = (state: GameState): TileGrid | null => {
  const opaque = state.floor.geometry.opaque;

  if (!isTileGridRecord(opaque)) {
    return null;
  }

  return opaque as unknown as TileGrid;
};

const checkMoveAction = (
  state: GameState,
  action: MoveAction,
): ActionLegality => {
  const grid = gridFromState(state);

  if (grid === null) {
    return illegal("floor geometry is not loaded");
  }

  const destination = destinationForMove(state.player.position, action.direction);

  if (!inBounds(grid, destination)) {
    return illegal(
      `move ${action.direction} leaves the map at (${destination.x}, ${destination.y})`,
    );
  }

  const tile = getTile(grid, destination);

  if (!isWalkableTile(tile)) {
    return illegal(`terrain ${tile.terrain} blocks movement`);
