 92	  );
 93	  const candidates = moves
 94	    .map((action) => {
 95	      const destination = moveDestination(
 96	        view.player.position,
 97	        action.direction
 98	      );
 99	      const nearestEnemyDistance = Math.min(
100	        ...view.visible.enemies.map((enemy) =>
101	          chebyshev(destination, enemy.position)
102	        )
103	      );
104	      const trapPenalty = trapKeys.has(key(destination)) ? 100 : 0;
105	      return { action, destination, score: nearestEnemyDistance - trapPenalty };
106	    })
107	    .filter((candidate) => candidate.score > 0)
108	    .sort((left, right) => {
109	      if (left.score !== right.score) {
110	        return right.score - left.score;
111	      }
112	      return key(left.destination).localeCompare(key(right.destination));
113	    });
114	
115	  return candidates[0]?.action ?? null;
116	};
